b:if.b:template-skin:

body#layout::before{content:'Om Muruga Framework v6.5 Engineered Internally';position:absolute;top:15px;right:15px;font-size:.8rem;font-family:Roboto, sans-serif;color:rgba(0,0,0,0.52)} 
body#layout{width:100%;max-width:1200px;margin:0 auto !important;padding:60px 20px 0 20px !important;border:0 !important;} 
body#layout .mainIn{margin-top:40px;padding-bottom:0} 
body#layout .mainIn::before{content:'Main Content'} 
body#layout footer::before{content:'Footer'}

head.b:skin:
:root {
  --headC: #1a1a2e; --bodyC: #333333; --bodyB: #f8f9fa; 
  --linkC: #d4af37; --linkB: #1a1a2e; --fffC: #ffffff; 
  --glassB: rgba(255,255,255,0.78); --glassD: rgba(26,26,46,0.88);
  --borderC: rgba(212,175,55,0.24); --shadowSoft: 0 18px 48px rgba(14,18,35,0.12);
  --headerH: 78px;
  --fontH: 'Playfair Display', serif; --fontB: 'Segoe UI', sans-serif;
}
html, body { margin: 0; padding: 0; font-family: var(--fontB); background: var(--bodyB); color: var(--bodyC); scroll-behavior: smooth; }
h1, h2, h3, h4, h5, h6 { margin: 0; font-weight: 700; font-family: var(--fontH); color: var(--headC); line-height: 1.4em; }
a { color: var(--linkC); text-decoration: none; transition: 0.3s; }
a:hover { opacity: 0.8; }
.secIn { margin: 0 auto; padding: 0 20px; max-width: 1200px; }

.progress-container { width: 100%; height: 4px; background: var(--headC); position: fixed; top: 0; z-index: 1001; }
.progress-bar { height: 4px; background: var(--linkC); width: 0%; }

.top-bar-wrapper { background: #f4f6fd; border-bottom: 1px solid #e1e5f2; color: #555; font-size: 13px; font-weight: 500; }
.top-bar { display: flex; justify-content: space-between; align-items: center; padding: 8px 20px; max-width: 1200px; margin: 0 auto; }
.top-contact { display: flex; gap: 20px; }
.top-contact a { color: #555; display: inline-flex; align-items: center; gap: 6px; }
.top-contact a:hover { color: var(--linkC); }
.top-contact svg { width: 14px; height: 14px; fill: currentColor; }
.top-social { display: flex; gap: 15px; }
.top-social a { color: #1a1a2e; transition: 0.3s; }
.top-social svg { width: 15px; height: 15px; fill: currentColor; }
.top-social a:hover { color: var(--linkC); transform: translateY(-2px); }

header { width: 100%; z-index: 1000; position: sticky; top:0; background: var(--glassD); color: var(--fffC); border-bottom: 1px solid rgba(212,175,55,0.58); box-shadow: 0 16px 40px rgba(0,0,0,0.14); backdrop-filter: blur(14px); -webkit-backdrop-filter: blur(14px);}
.headIn { display: flex; justify-content: space-between; align-items: center; height: var(--headerH); gap: 24px; position: relative;}
.headL { display: flex; align-items: center; }
.headF { flex: 1; display: flex; justify-content: center; }
.headR { display: flex; align-items: center; }

.mobile-menu-btn { display: none; color: #fff; font-size: 28px; cursor: pointer; padding: 5px; user-select: none; margin-right: 15px;}
#menu-nav-menu { display: flex; align-items: center; list-style: none; margin: 0; padding: 0; gap: 2px; position: relative; }
#menu-nav-menu > li { position: relative; }
#menu-nav-menu > li > a { color: var(--fffC); padding: 26px 14px; display: block; font-weight: 500; text-transform: uppercase; font-size: 13px; letter-spacing: 0.04em; }
#menu-nav-menu > li:hover > a, #menu-nav-menu > li:focus-within > a { color: var(--linkC); }
.has-submenu > a::after, .has-mega > a::after { content: "\25BC";  /* ▼ */; display: inline-block; font-size: 9px; margin-left: 8px; vertical-align: middle; }

.submenu { display: none; position: absolute; top: 100%; left: 0; min-width: 220px; background: #ffffff; border: 1px solid rgba(212, 175, 55, 0.55); box-shadow: 0 18px 36px rgba(0,0,0,0.18); list-style: none; margin: 0; padding: 10px 0; z-index: 1002; border-top: 3px solid var(--linkC); border-radius: 0 0 4px 4px;}
.submenu li { width: 100%; }
.submenu li a { display: block; padding: 14px 18px; color: var(--headC); font-size: 14px; font-weight: 600; text-transform: none; background: #ffffff; }
.submenu li a:hover { background: #f6f0db; color: #9d7411; opacity: 1; padding-left: 25px;}
.has-submenu:hover .submenu, .has-submenu:focus-within .submenu { display: block; }

.has-mega { position: static !important; }
.mega-menu { position: absolute; top: 100%; left: 0; width: 100%; background: #fff; display: none; padding: 30px; grid-template-columns: repeat(4, 1fr); gap: 20px; box-shadow: 0 10px 30px rgba(0,0,0,0.1); border-top: 3px solid #d4af37; z-index: 1002; border-radius: 0 0 8px 8px;}
.has-mega:hover .mega-menu { display: grid; }
.mega-menu div { display: flex; flex-direction: column; }
.mega-menu h4 { color: #d4af37; margin-bottom: 15px; font-size: 16px; border-bottom: 1px solid #eee; padding-bottom: 10px;}
.mega-menu a { color: #1a1a2e !important; padding: 8px 0 !important; font-weight: 600 !important; font-size: 14px;}
.mega-menu a:hover { color: #d4af37 !important; padding-left: 5px !important; }

.blogCont { padding: 40px 0; }
.layout-wrapper { display: flex; flex-wrap: wrap; gap: 30px; }
.mainbar { flex: 1; min-width: 0; }
.sidebar-widget-area { width: 320px; flex-shrink: 0; }

.error-wrap { text-align: center; padding: 100px 20px; background: #fff; border-radius: 12px; margin: 40px auto; max-width: 800px; box-shadow: 0 5px 30px rgba(0,0,0,0.05); }
.error-wrap h1 { font-size: 64px; color: #d4af37; margin-bottom: 10px; font-family: var(--fontH); }
.error-wrap p { font-size: 18px; color: #666; margin-bottom: 30px; }

.hero { height: 90vh; background: url('https://images.unsplash.com/photo-1600596542815-ffad4c1539a9') center/cover scroll; display: flex; align-items: center; justify-content: center; text-align: center; position: relative; }
.hero::after { content:''; position:absolute; inset:0; background: rgba(26,26,46,0.7); z-index: 1; }
.hero-content { position: relative; z-index: 2; padding: 0 20px;}
.hero-title { font-family: 'Playfair Display', serif; font-size: 4rem; font-weight: 800; color: #ffffff; margin-bottom: 10px; text-shadow: 2px 2px 10px rgba(0,0,0,0.5); letter-spacing: -1px; }
.hero-subtitle { font-family: 'Playfair Display', serif; font-size: 1.8rem; font-weight: 600; color: #d4af37; margin-bottom: 20px; text-shadow: 1px 1px 5px rgba(0,0,0,0.8); }
.hero-desc { font-family: 'Segoe UI', sans-serif; font-size: 1.2rem; color: #f8f9fa; margin-bottom: 30px; line-height: 1.5; max-width: 800px; margin-left: auto; margin-right: auto; }
.hero-btn { background: #d4af37; padding: 16px 36px; color: #000; font-weight: 800; border-radius: 6px; display: inline-block; margin-top: 25px; font-size: 16px; text-transform: uppercase; transition: 0.3s; box-shadow: 0 10px 20px rgba(212,175,55,0.4); cursor:pointer;}
.hero-btn:hover { transform: translateY(-3px); box-shadow: 0 15px 25px rgba(212,175,55,0.6); }

.submit-popup-overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.8); z-index: 10005; backdrop-filter: blur(5px); }
.submit-popup { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); background: var(--glassB); padding: 25px; border-radius: 8px; width: 90%; max-width: 650px; box-shadow: 0 20px 50px rgba(0,0,0,0.5); border: 1px solid rgba(255,255,255,0.4); backdrop-filter: blur(14px); -webkit-backdrop-filter: blur(14px); }
.close-submit-popup { position: absolute; top: 15px; right: 15px; background: #1a1a2e; color: #fff; width: 30px; height: 30px; border-radius: 50%; text-align: center; line-height: 30px; cursor: pointer; font-weight: bold; font-size: 14px; box-shadow: 0 4px 10px rgba(0,0,0,0.3); transition:0.3s;}
.close-submit-popup:hover { background: #d4af37; color:#000;}

.blogPts { display: grid; grid-template-columns: repeat(auto-fill, minmax(320px, 1fr)); gap: 30px; }
.property-card { position: relative; backdrop-filter: blur(14px); -webkit-backdrop-filter: blur(14px); background: var(--glassB); border-radius: 8px; box-shadow: 0 4px 15px rgba(0,0,0,0.08); overflow: hidden; display: flex; flex-direction: column; transition: transform 0.28s ease, box-shadow 0.28s ease, border-color 0.28s ease; border: 1px solid var(--borderC);}
.property-card::before { content: ''; position: absolute; inset: 0; border-radius: 8px; border: 1px solid transparent; pointer-events: none; transition: border-color 0.28s ease, box-shadow 0.28s ease; }
.property-card:hover { transform: translateY(-6px) scale(1.01); box-shadow: var(--shadowSoft); border-color: #d4af37;}
.property-card:hover::before { border-color: rgba(212,175,55,0.58); box-shadow: inset 0 0 0 1px rgba(255,255,255,0.3); }
.property-image { position: relative; height: 220px; width: 100%; overflow: hidden; }
.property-image img { width: 100%; height: 100%; object-fit: cover; transition: 0.5s; }
.property-card:hover .property-image img { transform: scale(1.05); }
.property-meta { position: absolute; top: 15px; left: 15px; display: flex; gap: 8px; flex-wrap: wrap; z-index: 2; }
.badge { background: #d4af37; color: #000; padding: 5px 12px; font-size: 12px; font-weight: 700; border-radius: 4px; box-shadow: 0 2px 5px rgba(0,0,0,0.2); text-transform: uppercase; letter-spacing: 0.5px;}
.badge.type-badge { background: #1a1a2e; color: #fff; }
.badge.sold { background: #ff4757 !important; color: #fff !important; }

.property-info { padding: 25px; display: flex; flex-direction: column; flex-grow: 1; }
.prop-price { color: #d4af37; font-size: 22px; font-weight: 800; margin-bottom: 10px; font-family: var(--fontB); }
.property-info h3 { font-size: 20px; margin-bottom: 12px; line-height: 1.4; font-family: var(--fontH); }
.property-info h3 a { color: #1a1a2e; text-decoration: none; }
.property-info h3 a:hover { color: #d4af37; }
.property-info p { color: #666; font-size: 14px; line-height: 1.6; margin-bottom: 20px; flex-grow: 1; }
.view-btn { display: block; text-align: center; background: #f8f9fa; color: #1a1a2e; border: 2px solid #1a1a2e; padding: 12px; border-radius: 6px; font-weight: bold; text-transform: uppercase; font-size: 13px; transition: transform 0.22s ease, box-shadow 0.22s ease, background 0.22s ease; }
.view-btn:hover { background: #1a1a2e; color: #fff; border-color: #1a1a2e; transform: translateY(-2px); box-shadow: 0 10px 20px rgba(26,26,46,0.18);}

.property-detail-wrapper { background: #fff; border-radius: 8px; padding: 40px; box-shadow: 0 5px 30px rgba(0,0,0,0.05); margin: 0 0 40px 0;}
.property-title { font-size: 38px; color: #1a1a2e; margin-bottom: 25px; font-family: var(--fontH); }
.property-gallery-hero { border-radius: 8px; overflow: hidden; margin-bottom: 30px; box-shadow: 0 5px 15px rgba(0,0,0,0.1); }
.property-gallery-hero img { width: 100%; max-height: 500px; object-fit: cover; display: block; }

.breadcrumb { font-size: 13px; color: #777; margin-bottom: 20px; font-weight: 500;}
.breadcrumb a { color: #1a1a2e; font-weight: 700; text-transform: uppercase; }
.breadcrumb a:hover { color: #d4af37; }

.property-specs { display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 15px; background: #f8f9fa; padding: 25px; border-radius: 8px; margin: 25px 0; border: 1px solid #eee; border-left: 4px solid #d4af37;}
.property-specs p { margin: 0; font-size: 16px; color: #333; font-weight: 600;}
.property-specs strong { color: #888; display: block; font-size: 12px; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 4px;}

.gallery { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 15px; margin: 30px 0; }
.gallery img { width: 100%; height: 160px; object-fit: cover; border-radius: 8px; cursor: pointer; transition: 0.3s; border: 1px solid #eee;}
.gallery img:hover { transform: scale(1.05); box-shadow: 0 10px 20px rgba(0,0,0,0.15);}
.post-body img { display: block; max-width: 100%; height: auto; margin: 18px auto; border-radius: 8px; box-shadow: 0 12px 30px rgba(0,0,0,0.10); background: #f0f2f5; }
.hidden-original { display: block !important; opacity: 1 !important; height: auto !important; position: static !important; overflow: visible !important; pointer-events: auto !important; }

.property-details { font-size: 17px; line-height: 1.8; color: #444; margin-bottom: 40px; }
.property-cta { display: flex; gap: 15px; flex-wrap: wrap; margin-top: 30px; padding-top: 30px; border-top: 1px solid #eee; }
.cta-btn { padding: 15px 30px; border-radius: 6px; font-weight: bold; font-size: 16px; text-align: center; flex: 1; min-width: 200px; transition: 0.3s; display: inline-flex; align-items: center; justify-content: center; gap: 10px;}
.cta-btn.wa-btn { background: #25D366; color: #fff; }
.cta-btn.wa-btn:hover { background: #1ebd5c; }
.cta-btn.call-btn { background: #1a1a2e; color: #d4af37; border: 1px solid #d4af37; }
.cta-btn.call-btn:hover { background: #d4af37; color: #1a1a2e; }

/* 🚨 5. STICKY SEARCH BAR DESIGN (Now visible on all pages) */
.property-filter-wrap { background: var(--glassB); padding: 20px 25px; border-radius: 8px; box-shadow: 0 10px 30px rgba(0,0,0,0.15); max-width: 1000px; margin: 25px auto 40px; display: flex; gap: 15px; position: relative; z-index: 10; flex-wrap: wrap; justify-content: space-between; align-items: center; border: 1px solid rgba(255,255,255,0.58); backdrop-filter: blur(14px); -webkit-backdrop-filter: blur(14px);}
.property-filter-wrap input { flex: 2; min-width: 200px; padding: 15px; border: 1px solid #ddd; border-radius: 6px; font-size: 15px; font-family: var(--fontB); color: #333; outline: none; transition: 0.3s; }
.property-filter-wrap select { flex: 1; min-width: 150px; padding: 15px; border: 1px solid #ddd; border-radius: 6px; font-size: 15px; font-family: var(--fontB); color: #333; outline: none; transition: 0.3s; }
.property-filter-wrap input:focus, .property-filter-wrap select:focus { border-color: #d4af37; box-shadow: 0 0 0 3px rgba(212, 175, 55, 0.2); }
.property-filter-wrap button { background: linear-gradient(135deg, #d4af37, #c99f2e); color: #000; border: none; padding: 15px 35px; font-weight: 800; font-size: 15px; text-transform: uppercase; border-radius: 6px; cursor: pointer; transition: 0.3s; flex-shrink: 0; }
.property-filter-wrap button:hover { transform: translateY(-2px); box-shadow: 0 5px 15px rgba(212, 175, 55, 0.4); }
.instant-search-results { display: none; flex: 1 1 100%; background: #fff; border: 1px solid #eee; border-radius: 8px; box-shadow: 0 16px 34px rgba(0,0,0,0.12); overflow: hidden; }
.instant-search-results.active { display: block; }
.instant-result { display: grid; grid-template-columns: 72px 1fr; gap: 12px; align-items: center; padding: 10px; border-bottom: 1px solid #f0f0f0; color: #1a1a2e; }
.instant-result:last-child { border-bottom: none; }
.instant-result img { width: 72px; height: 54px; object-fit: cover; border-radius: 6px; background: #f0f2f5; }
.instant-result strong { display: block; font-size: 14px; line-height: 1.35; color: #1a1a2e; }
.instant-result span { display: block; font-size: 12px; color: #777; margin-top: 4px; }
.instant-empty { padding: 14px; color: #666; font-size: 13px; text-align: center; }

.in-article-ad { clear: both; margin: 34px 0; padding: 18px 12px; background: #fbfbfb; border: 1px solid #ededed; border-radius: 8px; text-align: center; min-height: 120px; }
.ad-label { display: block; margin-bottom: 8px; color: #999; font-size: 10px; letter-spacing: 0.14em; text-transform: uppercase; }    

.seo-hub-section, .roi-tools-section, .video-proof-section { padding: 58px 0; background: #fff; border-top: 1px solid #eee; }
.seo-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(210px, 1fr)); gap: 16px; }
.seo-link-card { display: block; padding: 22px; border: 1px solid var(--borderC); border-radius: 8px; background: #fff; color: #1a1a2e; box-shadow: 0 5px 18px rgba(0,0,0,0.04); transition: 0.28s ease; }
.seo-link-card:hover { transform: translateY(-4px); box-shadow: var(--shadowSoft); border-color: #d4af37; opacity: 1; }
.seo-link-card strong { display: block; color: #1a1a2e; margin-bottom: 8px; font-size: 16px; }
.seo-link-card span { display: block; color: #666; font-size: 13px; line-height: 1.5; }
.tools-grid { display: grid; grid-template-columns: minmax(260px, 1fr) minmax(260px, 1fr); gap: 24px; }
.tool-panel { background: #f8f9fa; border: 1px solid #eee; border-radius: 8px; padding: 24px; }
.tool-panel h3 { font-size: 22px; margin-bottom: 16px; }
.tool-panel label { display: block; font-size: 13px; font-weight: 700; color: #555; margin: 12px 0 6px; }
.tool-panel input { width: 100%; box-sizing: border-box; padding: 12px 14px; border: 1px solid #ddd; border-radius: 6px; font-size: 14px; }
.tool-panel button { margin-top: 14px; background: #1a1a2e; color: #d4af37; border: 1px solid #d4af37; border-radius: 6px; padding: 12px 18px; font-weight: 800; cursor: pointer; transition: 0.24s ease; }
.tool-panel button:hover { transform: translateY(-2px); background: #d4af37; color: #1a1a2e; }
.roi-result, .compare-result { margin-top: 16px; padding: 14px; background: #fff; border-radius: 6px; color: #1a1a2e; font-weight: 700; min-height: 22px; }
.compare-table { width: 100%; border-collapse: collapse; margin-top: 14px; font-size: 13px; }
.compare-table th, .compare-table td { border-bottom: 1px solid #e5e5e5; padding: 9px 6px; text-align: left; }
.compare-table th { color: #777; font-size: 11px; text-transform: uppercase; letter-spacing: 0.08em; }
.video-proof { display: grid; grid-template-columns: 1.1fr 0.9fr; gap: 28px; align-items: center; }
.video-shell { position: relative; overflow: hidden; border-radius: 8px; min-height: 280px; background: linear-gradient(135deg, rgba(26,26,46,0.92), rgba(0,0,0,0.62)), url('https://images.unsplash.com/photo-1600585154340-be6161a56a0c') center/cover; box-shadow: var(--shadowSoft); }
.video-play { position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; color: #1a1a2e; }
.video-play span { width: 76px; height: 76px; border-radius: 50%; background: #d4af37; display: flex; align-items: center; justify-content: center; font-size: 34px; box-shadow: 0 14px 30px rgba(0,0,0,0.24); }
.video-copy p { color: #555; line-height: 1.7; }

/* 🚨 5. INTERNAL LINKING BOOST */
.internal-links { margin-top: 40px; display: flex; gap: 12px; flex-wrap: wrap; padding-top: 30px; border-top: 2px dashed #eee;}
.internal-links span { display: block; width: 100%; font-weight: bold; font-size: 20px; color: #1a1a2e; font-family: var(--fontH); margin-bottom: 10px;}
.internal-links a { background: #f4f6fd; color: #1a1a2e; padding: 10px 20px; border-radius: 4px; font-size: 13px; font-weight: bold; text-transform: uppercase; border: 1px solid #d4af37; transition: 0.3s;}
.internal-links a:hover { background: #1a1a2e; color: #d4af37; }

.google-reviews { background: #fff; padding: 20px; border-radius: 8px; text-align: center; font-weight: bold; color: #1a1a2e; margin: 30px 0; border: 1px solid #eee; box-shadow: 0 4px 15px rgba(0,0,0,0.05); }
.google-reviews span { color: #f39c12; font-size: 24px; letter-spacing: 2px; }

.sidebar-widget { background: #fff; border-radius: 8px; padding: 25px; box-shadow: 0 5px 20px rgba(0,0,0,0.05); margin-bottom: 30px; border: 1px solid #eee; }
.sidebar-widget h3 { font-size: 18px; margin-bottom: 20px; color: #1a1a2e; border-left: 4px solid #d4af37; padding-left: 10px; font-family: var(--fontH);}
.sidebar-widget input, .sidebar-widget select { width: 100%; padding: 12px 15px; margin-bottom: 15px; border: 1px solid #ddd; border-radius: 6px; font-size: 14px; outline: none; box-sizing: border-box; }
.sidebar-widget input:focus, .sidebar-widget select:focus { border-color: #d4af37; }
.sidebar-widget button { width: 100%; background: linear-gradient(135deg, #d4af37, #c99f2e); color: #000; border: none; padding: 14px; font-weight: 800; border-radius: 6px; cursor: pointer; transition: 0.3s; }
.sidebar-widget button:hover { box-shadow: 0 5px 15px rgba(212, 175, 55, 0.4); transform: translateY(-2px);}

.sticky-cta { position: fixed; bottom: 20px; left: 20px; background: #d4af37; padding: 14px 24px; border-radius: 50px; z-index: 9999; box-shadow: 0 4px 15px rgba(0,0,0,0.3); transition: 0.3s; display: flex; align-items: center; gap: 8px;}
.sticky-cta a { color: #000; font-weight: 800; font-size: 15px; text-decoration: none; }
.sticky-cta:hover { transform: scale(1.05); background: #f2ce5e;}

.exit-popup-overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.8); z-index: 10005; backdrop-filter: blur(5px); }
.exit-popup { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); background: rgba(26,26,46,0.92); padding: 40px; border-radius: 8px; border: 2px solid #d4af37; width: 90%; max-width: 450px; text-align: center; color: #fff; box-shadow: 0 20px 50px rgba(0,0,0,0.5); backdrop-filter: blur(14px); -webkit-backdrop-filter: blur(14px); }
.exit-popup h2 { color: #d4af37; font-size: 24px; margin-bottom: 10px; font-family: var(--fontH); }
.exit-popup p { margin-bottom: 20px; font-size: 15px; opacity: 0.9; }
.exit-popup select, .exit-popup input { width: 100%; padding: 15px; margin-bottom: 15px; border: none; border-radius: 6px; box-sizing: border-box; font-family: var(--fontB); font-size: 15px;}
.exit-popup button { width: 100%; background: linear-gradient(135deg, #d4af37, #c99f2e); color: #000; border: none; padding: 15px; font-weight: 800; font-size: 16px; border-radius: 6px; cursor: pointer; transition: 0.3s; }
.exit-popup button:hover { transform: translateY(-2px); box-shadow: 0 5px 15px rgba(212, 175, 55, 0.4); }
.close-popup { position: absolute; top: 15px; right: 15px; color: #fff; cursor: pointer; font-size: 24px; line-height: 1; }

.construction-trust { background: #1a1a2e; color: #fff; padding: 60px 0; }
.section-header { text-align: center; margin-bottom: 40px; }
.section-header h2 { color: #fff; font-size: 32px; font-weight: 700; margin-bottom: 10px; font-family: var(--fontH);}
.section-header h2.dark-text { color: #1a1a2e; }
.section-line { width: 60px; height: 3px; background: linear-gradient(90deg, #d4af37, #c99f2e); margin: 0 auto; }
.const-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 20px; text-align: center; }
.const-card { padding: 30px 20px; border: 1px solid rgba(212,175,55,0.2); border-radius: 8px; background: rgba(0,0,0,0.2); transition: 0.3s;}
.const-card:hover { transform: translateY(-5px); border-color: #d4af37; background: rgba(212,175,55,0.05); }
.const-card h3 { color: #d4af37; font-size: 36px; margin-bottom: 10px; font-family: var(--fontH);}
.const-card p { color: #ddd; font-size: 15px; font-weight: 500; margin: 0; line-height: 1.5;}

.great-features { background: #111; color: #fff; padding: 60px 0; border-top: 1px solid #333;}
.gf-grid { display: grid; grid-template-columns: 1fr 320px 1fr; gap: 30px; align-items: center; margin-top: 40px; }
.gf-item { background: #1a1a1a; border: 1px solid #333; padding: 20px; border-radius: 8px; display: flex; align-items: center; gap: 15px; margin-bottom: 20px; border-left: 3px solid #d4af37; transition: 0.3s;}
