.gf-icon { width: 50px; height: 50px; background: linear-gradient(135deg, #d4af37, #c99f2e); border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 20px; flex-shrink: 0; color: #000;}
.gf-text h3 { font-size: 16px; color: #fff; margin-bottom: 5px; }
