.tab-parent { background: #fefefe; padding: 60px 0; border-top: 1px solid #eee; border-bottom: 1px solid #eee; }
.bow { display: flex; flex-wrap: wrap; margin-left: -30px; align-items: center;}
.breedum { width: calc(100% / 3); padding-left: 30px; box-sizing: border-box; }
.sring img { width: 100%; height: auto; border-radius: 8px; }
.dring { margin-bottom: 30px; padding: 25px; background: #fff; box-shadow: 0 5px 20px rgba(0,0,0,0.05); border-radius: 8px; transition: 0.3s; display: flex; align-items: flex-start;}
.dring:hover { transform: translateY(-3px); box-shadow: 0 10px 25px rgba(0,0,0,0.1); border-left: 3px solid #d4af37;}
