.vm-image img { width: 100%; border-radius: 12px; box-shadow: 0 10px 40px rgba(0,0,0,0.15); }
.vm-content h3 { font-size: 15px; text-transform: uppercase; letter-spacing: 1px; color: #d4af37; border-bottom: 2px solid #d4af37; display: inline-block; padding-bottom: 5px; margin-bottom: 25px;}
.vm-block { margin-bottom: 30px; }
