.testimonials-section { background: #f8f9fa; padding: 60px 0; border-top: 1px solid #eee; }
.testimonial-slider-wrap { overflow: hidden; width: 100%; position: relative; }
.testimonial-slider { display: flex; position: relative; width: 100%; transition: transform 0.5s ease; }
.testi-item { min-width: 100%; text-align: center; padding: 40px 30px; background: #fff; border-radius: 10px; box-shadow: 0 5px 20px rgba(0,0,0,0.05); border-bottom: 3px solid #d4af37; box-sizing: border-box; }
.testi-item p { font-style: italic; color: #555; font-size: 16px; line-height: 1.7; margin-bottom: 20px;}
