.counter-container { background: linear-gradient(135deg, #d4af37 0%, #c99f2e 100%); padding: 30px 20px; margin: 16px auto; border-radius: 8px; box-shadow: 0 8px 24px rgba(212, 175, 55, 0.2); max-width: 1000px; width: 100%; } 
.counter-wrapper { display: grid; grid-template-columns: repeat(4, minmax(130px, 1fr)); gap: 20px; width: 100%; align-items: flex-start; } 
.counter { background: #000000; padding: 20px; border-radius: 10px; text-align: center; transition: all 0.3s ease; box-shadow: 0 4px 10px rgba(0, 0, 0, 0.12); display: flex; flex-direction: column; align-items: center; justify-content: flex-start; } 
.counter:hover { transform: translateY(-3px); box-shadow: 0 7px 18px rgba(0, 0, 0, 0.18); } 
.counter-icon { font-size: 36px; margin-bottom: 10px; display: block; } 
