.counter-title { font-size: 14px; font-weight: 600; color: #d4af37; margin: 0; line-height: 1.4; } 

.floating-tools { position: fixed; bottom: 20px; right: 20px; z-index: 998; display: flex; flex-direction: column; gap: 15px; align-items: flex-end;}
.float-btn { display: flex; align-items: center; justify-content: center; width: 60px; height: 60px; border-radius: 50%; box-shadow: 0 4px 15px rgba(0,0,0,0.2); transition: 0.3s; font-size: 24px; color: #fff; }
.float-btn:hover { transform: scale(1.1); color: #fff; }
.btn-wa { background: #25D366; animation: pulse 2s infinite; }
@keyframes pulse {
  0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(37, 211, 102, 0.7); }
  70% { transform: scale(1.05); box-shadow: 0 0 0 15px rgba(37, 211, 102, 0); }
  100% { transform: scale(1); box-shadow: 0 0 0 0 rgba(37, 211, 102, 0); }
}

footer { background: #050505; color: #d9d9d9; padding: 54px 0 34px; margin-top: 0; text-align: center; border-top: 4px solid var(--linkC);}
.footer-links { margin: 0 0 28px; list-style: none; padding: 0; display: flex; flex-wrap: wrap; justify-content: center; gap: 14px; }
.footer-links li { display: inline-flex; align-items: center; }
.footer-links li:not(:last-child)::after { content: "\2022";  /* • */; color: rgba(255,255,255,0.55); margin-left: 14px; }
.footer-links a { color: #fff; text-transform: uppercase; font-size: 13px; font-weight: 700; letter-spacing: 0.08em; }
.footer-copy { max-width: 980px; margin: 0 auto 26px; color: #ffffff; font-size: 16px; line-height: 1.55; font-weight: 700; }

@media (max-width: 1024px) {
  .hero-title { font-size: 3rem; }
  .headIn { padding: 14px 0; }
  .bow { margin-left: 0; }
  .breedum { width: 100%; padding-left: 0; margin-bottom: 20px; }
  .sbreed { text-align: center; }
  .sring img { max-width: 500px; margin: 0 auto; }
  .counter-wrapper { grid-template-columns: repeat(2, 1fr); gap: 15px;}
  .gf-grid { grid-template-columns: 1fr 1fr; }
  .gf-center { grid-column: 1 / -1; order: -1; margin-bottom: 20px; }
  .gf-center img { max-width: 300px; }
  .vm-grid { grid-template-columns: 1fr; gap: 30px; }
  .sidebar-widget-area { width: 100%; }
  .property-filter-wrap input, .property-filter-wrap select { min-width: 100%; }
  .tools-grid, .video-proof { grid-template-columns: 1fr; }
}

@media (min-width: 1025px) {
  .sidebar-widget.sticky-sidebar-ad { position: sticky; top: 100px; z-index: 4; }
}

@media (max-width: 900px) {
  .mobile-menu-btn { display: block; }
  .headF { position: absolute; top: 100%; left: 0; width: 100%; background: #1a1a2e; z-index: 999; }
  #menu-nav-menu { display: none; flex-direction: column; width: 100%; padding: 0; box-shadow: 0 10px 20px rgba(0,0,0,0.2); }
  #menu-nav-menu.show-mobile-menu { display: flex; }
  #menu-nav-menu > li { width: 100%; }
  #menu-nav-menu > li > a { padding: 15px 20px; border-bottom: 1px solid rgba(255,255,255,0.05); }
  .submenu, .mega-menu { position: static; box-shadow: none; border-top: none; background: #111122; display: none; padding-left: 15px;}
  .mega-menu { grid-template-columns: 1fr; padding: 15px; }
  .has-submenu:hover .submenu, .has-submenu:focus-within .submenu, .has-mega:hover .mega-menu { display: block; }
  .submenu li a, .mega-menu a { color: #fff !important; background: transparent; }
  .submenu li a:hover, .mega-menu a:hover { background: rgba(255,255,255,0.1); color: #d4af37 !important;}
}

@media (max-width: 768px) {
  body { padding-bottom: 74px; }
  .top-bar { flex-direction: column; gap: 10px; padding: 10px; }
  .top-contact { flex-direction: column; gap: 5px; text-align: center; }
  .hero-title { font-size: 2.2rem; }
  .property-filter-wrap { flex-direction: column; margin: -20px 15px 30px; position: relative; top: 0; }
  .property-filter-wrap button { width: 100%; }
  .property-detail-wrapper { padding: 20px; margin: 20px 10px; }
  .property-title { font-size: 28px; }
  .sticky-cta { bottom: 84px; left: 12px; padding: 12px 18px; }
  .floating-tools { bottom: 84px; right: 12px; }
  .seo-hub-section, .roi-tools-section, .video-proof-section { padding: 42px 0; }
  .footer-links { flex-direction: column; gap: 10px; }
  .footer-links li:not(:last-child)::after { content: ''; margin-left: 0; }
  .footer-copy { font-size: 15px; }
  .counter-wrapper { grid-template-columns: repeat(2, minmax(130px, 1fr)); }
  .gf-grid { grid-template-columns: 1fr; }
}

@media (prefers-color-scheme: dark) {
  :root { --bodyB: #10131c; --bodyC: #e6e8ee; --headC: #f6f0db; --glassB: rgba(22,26,38,0.82); }
  html, body { background: var(--bodyB); color: var(--bodyC); }
  .property-card, .property-detail-wrapper, .property-filter-wrap, .sidebar-widget, .testi-item, .seo-link-card, .tool-panel, .roi-result, .compare-result { background: rgba(22,26,38,0.88); color: #e6e8ee; border-color: rgba(212,175,55,0.22); }
  .property-info h3 a, .seo-link-card strong, .tool-panel h3, .roi-result, .compare-result { color: #f6f0db; }
  .property-info p, .seo-link-card span, .video-copy p, .tool-panel label { color: #c8ccd8; }
  .top-bar-wrapper, .testimonials-section, .tab-parent, .vision-mission-section, .seo-hub-section, .roi-tools-section, .video-proof-section { background: #141824; border-color: rgba(255,255,255,0.08); }
  .property-filter-wrap input, .property-filter-wrap select, .tool-panel input, .instant-search-results { background: #0f1320; color: #fff; border-color: rgba(255,255,255,0.12); }
  .mobile-sticky-ad { background: #111521; border-color: rgba(255,255,255,0.12); }
}

b:if.script:
//
document.addEventListener("DOMContentLoaded", function() {
  // Explicitly fetch ONLY posts with the "Property" label
  fetch('/feeds/posts/summary/-/Property?alt=json&max-results=6')
  .then(response => response.json())
  .then(data => {
    let html = '';
    if (data.feed.entry && data.feed.entry.length > 0) {
      data.feed.entry.forEach(entry => {
        let title = entry.title.$t;
        let link = entry.link.find(l => l.rel === 'alternate').href;

        let imgUrl = 'https://images.unsplash.com/photo-1600596542815-ffad4c1539a9'; 
        if (entry.media$thumbnail) {
          imgUrl = entry.media$thumbnail.url.replace('/s72-c/', '/s600/');
        }

        let badgesHtml = '';
        let priceHtml = '';
        let snippet = entry.summary ? entry.summary.$t.substring(0, 115) + '...' : '';

        if (entry.category) {
          entry.category.forEach(cat => {
            let labelName = cat.term;
            // Updated to your new Property Types list
            if (["Plots", "Building", "Apartments", "Office Spaces", "Rental Properties", "Ware Houses Sale", "High ROI Layout", "Parcel Land", "Agricultural Land"].includes(labelName)) {
              badgesHtml += `<span class='badge type-badge'>${labelName}</span>`;
            }
            if (["Corner Plot", "Near Highway", "DTCP"].includes(labelName)) {
              badgesHtml += `<span class='badge' style='background:#1abc9c; color:#fff;'>${labelName}</span>`;
            }
            if (labelName === "Status:Sold") {
              badgesHtml += `<span class='badge sold'>Sold Out</span>`;
            }
            if (labelName === "Status:Available") {
              badgesHtml += `<span class='badge' style='background:#2ecc71; color:#fff;'>Available</span>`;
            }
            if (labelName === "Hot Deal") {
              badgesHtml += `<span class='badge' style='background:#ff6b00; color:#fff;'>Hot Deal</span>`;
            }
            if (labelName === "New Launch") {
              badgesHtml += `<span class='badge' style='background:#3498db; color:#fff;'>New Launch</span>`;
            }
            if (labelName.includes("Lakhs") || labelName.includes("Crore")) {
              priceHtml = `&#8377; ${labelName}`;
            }
          });
        }

        html += `
          <article class='property-card' data-aos='fade-up'>
            <div class='property-image'>
              <a href='${link}'><img src='${imgUrl}' alt='${title}'/></a>
              <div class='property-meta'>${badgesHtml}</div>
            </div>
            <div class='property-info'>
              ${priceHtml ? `<div class='prop-price'>${priceHtml}</div>` : ''}
              <h3><a href='${link}'>${title}</a></h3>
              <p>${snippet}</p>
              <a class='view-btn' href='${link}'>View Details</a>
            </div>
          </article>
        `;
      });
    } else {
      html = '<p style="text-align:center; grid-column: 1 / -1;">No properties available right now.</p>';
    }
    document.getElementById('premium-properties-grid').innerHTML = html;
  })
  .catch(error => console.error("Error fetching properties:", error));
});
