body.script:
  //

  function loadAOS() {
    if (window.AOS) {
      window.AOS.init({ once: true, offset: 120, duration: 800, easing: 'ease-in-out' });
      return;
    }
    if (document.getElementById('aosScript')) return;
    var aosScript = document.createElement('script');
    aosScript.id = 'aosScript';
    aosScript.src = 'https://unpkg.com/aos@2.3.4/dist/aos.js';
    aosScript.defer = true;
    aosScript.onload = function() {
      if (window.AOS) window.AOS.init({ once: true, offset: 120, duration: 800, easing: 'ease-in-out' });
    };
    document.body.appendChild(aosScript);
  }

  ['scroll', 'mousemove', 'touchstart', 'keydown'].forEach(function(evt) {
    window.addEventListener(evt, loadAOS, { once: true, passive: true });
  });
  setTimeout(loadAOS, 2500);

  (function installPwaShell() {
    try {
      var manifest = {
        name: 'Om Muruga Group of Companies',
        short_name: 'Om Muruga',
        start_url: '/',
        scope: '/',
        display: 'standalone',
        background_color: '#1a1a2e',
        theme_color: '#1a1a2e',
        icons: [{
          src: 'https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEhFAj8iQ6WBw9Y2EjsLVcwUPydEA7NkviK_vYwFjV72sJRXa6LgjGeG5IpE6LUu5gCDylo9N-uADF3x3SeOSSfy0r05HE_29nfKuEUoxmnS5GZuKZErWozA0-gMyEYitWLbJQ7JnmzcaFEU_WkBnxFfGNhXaeM0WcmYd5bCzToaomT1p35NEXGLovZpdPg/s4350/PNG.png',
          sizes: '512x512',
          type: 'image/png',
          purpose: 'any maskable'
        }]
      };
      var blob = new Blob([JSON.stringify(manifest)], { type: 'application/manifest+json' });
      var link = document.createElement('link');
      link.rel = 'manifest';
      link.href = URL.createObjectURL(blob);
      document.head.appendChild(link);
      if ('serviceWorker' in navigator) {
        window.addEventListener('load', function() {
          navigator.serviceWorker.register('/sw.js').catch(function() {});
        });
      }
    } catch (e) {}
  })();

  window.onscroll = function() {
    let winScroll = document.body.scrollTop || document.documentElement.scrollTop;
    let height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    let scrolled = (winScroll / height) * 100;
    let bar = document.getElementById("myBar");
    if(bar) bar.style.width = scrolled + "%";
  };

  document.addEventListener("click", function(e){
    let menu = document.getElementById("menu-nav-menu");
    let btn = document.querySelector(".mobile-menu-btn");
    if (menu && btn && !menu.contains(e.target) && !btn.contains(e.target)) {
      menu.classList.remove("show-mobile-menu");
    }
  });

  function openSubmitPopup() { document.getElementById("submitPopup").style.display="block"; }
  function closeSubmitPopup() { document.getElementById("submitPopup").style.display="none"; }

  // Updated Search Engine (Proper Multiple Labels Support)
  function executePropertyFilter() {
    let type = document.getElementById('propertyType').value;
    let keyword = document.getElementById('searchKeyword').value.trim();

    // 1. Always force the search to look for Properties
    let query = 'label:"Property"'; 

    // 2. Add the Location label if they typed one
    if (keyword) {
      query += ' label:"' + keyword + '"';
    }

    // 3. Add the Type label if they selected one
    if (type) {
      query += ' label:"' + type + '"';
    }

    // 4. Send tracking data and execute the search!
    if(typeof gtag !== 'undefined') gtag('event', 'search', { search_term: keyword + " " + type });
    window.location.href = "/search?q=" + encodeURIComponent(query);
  }

  function escapeHTML(value) {
    return String(value || '').replace(/[&<>"']/g, function(ch) {
      return ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[ch];
    });
  }

  function setupInstantSearch() {
    var input = document.getElementById('searchKeyword');
    var results = document.getElementById('instantSearchResults');
    if (!input || !results || !window.fetch) return;
    var timer;
    input.addEventListener('input', function() {
      var query = input.value.trim();
      clearTimeout(timer);
      if (query.length < 2) {
        results.classList.remove('active');
        results.innerHTML = '';
        return;
      }
      timer = setTimeout(function() {
        fetch('/feeds/posts/summary?q=' + encodeURIComponent(query) + '&alt=json&max-results=5')
          .then(function(response) { return response.json(); })
          .then(function(data) {
            var entries = data.feed && data.feed.entry ? data.feed.entry : [];
            if (!entries.length) {
              results.innerHTML = '<div class="instant-empty">No matching property found.</div>';
              results.classList.add('active');
              return;
            }
            results.innerHTML = entries.map(function(entry) {
              var title = entry.title ? entry.title.$t : 'Property';
              var link = (entry.link || []).find(function(item) { return item.rel === 'alternate'; });
              var img = entry.media$thumbnail ? entry.media$thumbnail.url.replace('/s72-c/', '/s160/') : 'https://images.unsplash.com/photo-1600596542815-ffad4c1539a9';
              var summary = entry.summary ? entry.summary.$t.replace(/<[^>]*>/g, '').substring(0, 74) : 'View property details';
              return '<a class="instant-result" href="' + escapeHTML(link ? link.href : '#') + '"><img loading="lazy" decoding="async" src="' + escapeHTML(img) + '" alt="' + escapeHTML(title) + '"/><span><strong>' + escapeHTML(title) + '</strong><span>' + escapeHTML(summary) + '</span></span></a>';
            }).join('');
            results.classList.add('active');
          })
          .catch(function() {
            results.classList.remove('active');
          });
      }, 260);
    });
  }

  function calculateROI() {
    var buy = parseFloat(document.getElementById('roiBuy').value) || 0;
    var value = parseFloat(document.getElementById('roiValue').value) || 0;
    var years = parseFloat(document.getElementById('roiYears').value) || 1;
    var result = document.getElementById('roiResult');
    if (!result) return;
    if (!buy || !value) {
      result.textContent = 'Enter purchase price and expected value.';
      return;
    }
    var totalReturn = ((value - buy) / buy) * 100;
    var annualReturn = totalReturn / Math.max(years, 1);
    result.textContent = 'Total ROI: ' + totalReturn.toFixed(1) + '% | Annualized estimate: ' + annualReturn.toFixed(1) + '%';
  }

  function addCompareRow() {
    var name = document.getElementById('compareName').value.trim() || 'Property';
    var price = parseFloat(document.getElementById('comparePrice').value) || 0;
    var area = parseFloat(document.getElementById('compareArea').value) || 0;
    var tbody = document.querySelector('#compareTable tbody');
    var result = document.getElementById('compareResult');
    if (!tbody || !result) return;
    if (!price || !area) {
      result.textContent = 'Enter price and area to compare.';
      return;
    }
    var perSqft = price / area;
    var row = document.createElement('tr');
    row.innerHTML = '<td>' + escapeHTML(name) + '</td><td>Rs. ' + price.toLocaleString() + '</td><td>' + area.toLocaleString() + '</td><td>Rs. ' + perSqft.toFixed(0) + '</td>';
    tbody.appendChild(row);
    result.textContent = 'Comparison updated. Lower per sq.ft can indicate better value after legal checks.';
  }

  function openLeadPopup() { document.getElementById('exitPopupOverlay').style.display = 'block'; }
  function closeLeadPopup() { document.getElementById('exitPopupOverlay').style.display = 'none'; }

  setTimeout(function() {
    if (!sessionStorage.getItem('leadPopupShown')) {
      openLeadPopup();
      sessionStorage.setItem('leadPopupShown', 'true');
    }
  }, 15000);

  function submitLead() {
    let name = document.getElementById('leadName').value;
    let phone = document.getElementById('leadPhone').value;
    let budget = document.getElementById('leadBudget').value;

    if(name && phone) {
      const googleAppScriptUrl = "https://script.google.com/macros/s/AKfycbxlPhXdpbx-D7dtOR4DUOQsyf8eWAwvODL-6BErY1pUMKVnxKVbzVgkY3n9t3zYPLHT7Q/exec";

      fetch(googleAppScriptUrl, {
        method: "POST", mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({name: name, phone: phone, budget: budget, source: 'Homepage Search Intent Lead'})
      });

      let waMessage = "Hi Om Muruga Construction, I am " + name + ". I am looking for property details. My budget is " + budget + ".";
      let waUrl = "https://wa.me/917373036360?text=" + encodeURIComponent(waMessage);
      closeLeadPopup();
      window.open(waUrl, '_blank');
    } else {
      alert('Please enter your name and WhatsApp number to proceed.');
    }
  }

  let testiIndex = 0;
  let testiTimer;

  function showTestimonial() {
    const testiItems = document.querySelectorAll('.testi-item');
    if(!testiItems.length) return;
    testiItems.forEach((item) => {
      item.style.transform = "translateX(" + (-testiIndex * 100) + "%)";
    });
  }

  function nextTesti() {
    const testiItems = document.querySelectorAll('.testi-item');
    if(!testiItems.length) return;
    testiIndex++;
    if (testiIndex >= testiItems.length) testiIndex = 0;
    showTestimonial();
    resetTestiTimer();
  }

  function prevTesti() {
    const testiItems = document.querySelectorAll('.testi-item');
    if(!testiItems.length) return;
    testiIndex--;
    if (testiIndex < 0) testiIndex = testiItems.length - 1;
    showTestimonial();
    resetTestiTimer();
  }

  function resetTestiTimer() {
    clearInterval(testiTimer);
    testiTimer = setInterval(nextTesti, 4000);
  }

  (function() {
    function animateCounter(element, finalValue) {
      if (element.classList.contains('counted')) return;
      element.classList.add('counted');
      const speed = parseInt(element.getAttribute('data-speed')) || 2000;
      const increment = finalValue / (speed / 16); 
      let current = 0;
      const timer = setInterval(function() {
        current += increment;
        if (current >= finalValue) { current = finalValue; clearInterval(timer); }
        element.textContent = Math.floor(current).toLocaleString();
      }, 16);
    }

    document.addEventListener('DOMContentLoaded', function() {
      const testiItems = document.querySelectorAll('.testi-item');
      if(testiItems.length > 0) { resetTestiTimer(); }
      setupInstantSearch();

      if ('IntersectionObserver' in window) {
        const observer = new IntersectionObserver(entries => {
          entries.forEach(entry => {
            if(entry.isIntersecting){
              animateCounter(entry.target, parseInt(entry.target.dataset.to));
            }
          });
        });
        document.querySelectorAll('.timer').forEach(el => observer.observe(el));
      } else {
        document.querySelectorAll('.timer').forEach(el => animateCounter(el, parseInt(el.dataset.to)));
      }

      let postBody = document.querySelector('.post-body.entry-content');
      let galleryContainer = document.getElementById('property-gallery-container');

      if (postBody) {
          let images = postBody.querySelectorAll('img');
          let title = postBody.getAttribute('data-post-title') || document.title.replace(/\|.*/, '').trim() || 'Om Muruga Property';
          images.forEach(function(img, index) {
              img.classList.remove('hidden-original');
              if (img.parentElement && img.parentElement.tagName === 'A') {
                  img.parentElement.style.display = '';
              }
              img.setAttribute('loading', 'lazy');
              img.setAttribute('decoding', 'async');
              if (!img.getAttribute('alt')) img.setAttribute('alt', title + ' image ' + (index + 1));
              if (!img.getAttribute('title')) img.setAttribute('title', img.getAttribute('alt'));
              if (!img.getAttribute('width') && img.naturalWidth) img.setAttribute('width', img.naturalWidth);
              if (!img.getAttribute('height') && img.naturalHeight) img.setAttribute('height', img.naturalHeight);
              img.addEventListener('load', function() {
                if (!img.getAttribute('width') && img.naturalWidth) img.setAttribute('width', img.naturalWidth);
                if (!img.getAttribute('height') && img.naturalHeight) img.setAttribute('height', img.naturalHeight);
              }, { once: true });
              if (galleryContainer && index > 0) {
                  let clonedImg = img.cloneNode(true);
                  galleryContainer.appendChild(clonedImg);
              }
          });

          let paragraphs = Array.prototype.slice.call(postBody.querySelectorAll('p')).filter(function(p) {
            return p.textContent.trim().length > 70 && !p.closest('.in-article-ad');
          });
          let insertedAds = 0;
          paragraphs.forEach(function(paragraph, index) {
            if ((index + 1) % 4 === 0 && insertedAds < 3) {
              let ad = document.createElement('div');
              ad.className = 'in-article-ad';
              ad.innerHTML = '<span class="ad-label">Advertisement</span><ins class="adsbygoogle" style="display:block; text-align:center;" data-ad-client="ca-pub-4724455892440922" data-ad-slot="4515428293" data-ad-layout="in-article" data-ad-format="fluid"></ins>';
              paragraph.parentNode.insertBefore(ad, paragraph.nextSibling);
              insertedAds++;
            }
          });
          for (let i = 0; i < insertedAds; i++) {
            try { (adsbygoogle = window.adsbygoogle || []).push({}); } catch(e) {}
          }

          let faqItems = [];
          let faqCandidates = Array.prototype.slice.call(postBody.querySelectorAll('h2,h3,h4,p'));
          faqCandidates.forEach(function(node) {
            let question = node.textContent.trim();
            if (faqItems.length >= 6 || question.indexOf('?') === -1 || question.length > 140) return;
            let answerNode = node.nextElementSibling;
            while (answerNode && !answerNode.textContent.trim()) answerNode = answerNode.nextElementSibling;
            let answer = answerNode ? answerNode.textContent.trim().replace(/\s+/g, ' ').substring(0, 420) : '';
            if (answer.length > 30) {
              faqItems.push({
                '@type': 'Question',
                name: question,
                acceptedAnswer: { '@type': 'Answer', text: answer }
              });
            }
          });
          if (faqItems.length && !document.getElementById('autoFaqSchema')) {
            let schema = document.createElement('script');
            schema.type = 'application/ld+json';
            schema.id = 'autoFaqSchema';
            schema.text = JSON.stringify({ '@context': 'https://schema.org', '@type': 'FAQPage', mainEntity: faqItems });
            document.head.appendChild(schema);
          }
      }

    });
  })();

